import os, base64, urllib.request, json, tempfile, subprocess

token = os.environ.get("GITHUB_TOKEN", "")
repo  = "dperuffo/estudo-de-rede"
SCRIPT_B64 = ""
script_bytes = base64.b64decode(SCRIPT_B64.encode())

# Sobe o script para o GitHub
url = "https://api.github.com/repos/" + repo + "/contents/estudo-de-rede/deploy_termos_fni_v2.py"
req = urllib.request.Request(url, headers={
    "Authorization": "token " + token,
    "Accept": "application/vnd.github.v3+json"
})
sha_existente = None
try:
    with urllib.request.urlopen(req) as r:
        sha_existente = json.loads(r.read()).get("sha")
except Exception:
    pass
payload = {"message": "chore: script deploy termos v2", "content": SCRIPT_B64}
if sha_existente:
    payload["sha"] = sha_existente
req2 = urllib.request.Request(url, data=json.dumps(payload).encode(), method="PUT", headers={
    "Authorization": "token " + token,
    "Content-Type": "application/json",
    "Accept": "application/vnd.github.v3+json"
})
with urllib.request.urlopen(req2) as r:
    result = json.loads(r.read())
    commit_sha = result["commit"]["sha"][:7]
    print("Script enviado ao GitHub: commit " + commit_sha)

# Salva e executa localmente
with tempfile.NamedTemporaryFile(suffix=".py", delete=False, mode="wb") as tmp:
    tmp.write(script_bytes)
    tmp_path = tmp.name
print("Executando deploy_termos_fni_v2.py...")
ret = subprocess.run(["python3", tmp_path], env=os.environ.copy())
if ret.returncode != 0:
    print("ERRO na execucao do script v2")